mapper.select:
SELECT
FROM posts p JOIN users u ON u.user_id = p.author_id JOIN categories c ON c.category_id = p.category_id LEFT JOIN post_i18n pi ON pi.post_id = p.post_id AND pi.language_code = p.original_language WHERE 1 = 1
AND p.status = #{status}
AND ( pi.title LIKE CONCAT('%', #{keyword}, '%') OR pi.summary LIKE CONCAT('%', #{keyword}, '%') OR u.username LIKE CONCAT('%', #{keyword}, '%') OR u.display_name LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY p.featured DESC, p.updated_time DESC, p.post_id DESC LIMIT #{limit}

mapper.update:
UPDATE posts
SET featured = #{featured}
WHERE post_id = #{postId}

UPDATE posts
SET status = #{status}
WHERE post_id = #{postId}

mapper.select:
SELECT
FROM reports r JOIN posts p ON p.post_id = r.post_id JOIN users reporter ON reporter.user_id = r.reporter_id LEFT JOIN users processor ON processor.user_id = r.processed_by LEFT JOIN post_i18n pi ON pi.post_id = p.post_id AND pi.language_code = p.original_language WHERE 1 = 1
AND r.status = #{status}
ORDER BY CASE WHEN r.status = 'PENDING' THEN 0 ELSE 1 END, r.created_time DESC LIMIT #{limit}

SELECT
FROM users u WHERE 1 = 1
AND u.status = #{status}
AND ( u.username LIKE CONCAT('%', #{keyword}, '%') OR u.display_name LIKE CONCAT('%', #{keyword}, '%') OR u.email LIKE CONCAT('%', #{keyword}, '%') )
ORDER BY u.created_time DESC, u.user_id DESC LIMIT #{limit}

SELECT

FROM users u
WHERE u.user_id = #{userId}

mapper.update:
